{%raw%}
<div style='width:100%;height:100%;'>
  <div style="width: 100%; height: 100%; display: flex; flex-direction: column; justify-content: center; align-items: center">
    <div style='text-align: center; margin-bottom: 8px; color: #424242; font-size: 14px;'>{{count_label}}</div>
    {% set raw = sensor_status or 'OK' %}
    {% set status = raw | string | lower %}
    {% if status in ['ok','up','normal','1'] %}
        {% set display = 'OK' %}
        {% set color = '#43a047' %}
{% elif status in ['warning'] %}
  {% set display = 'WARNING' %}
  {% set color = '#f39c12' %}
{% elif status in ['critical','down','failed'] %}
  {% set display = 'CRITICAL' %}
  {% set color = '#e53935' %}
{% else %}
  {% set display = 'OK' %}
  {% set color = '#43a047' %}
{% endif %}
    <div style="text-align: center; font-size: 24px; font-weight: 600; color: {{ color }};">{{ sensor_status or 'NA' }}</div>
  </div>
</div>
{%endraw%}

{% raw %}
{% set target_ip = context.target_ip %}
{% set power_query = "target_ip is '" ~ target_ip ~ "' and sensor_type_label is not empty" %}

{% set power_data = engine.query_stream_data(
    stream="rda_snmp_metrics",
    cfxql_query=power_query,
    sorting=[{"timestamp": "desc"}],
    limit=300,
    max_rows=300
) %}

{% set grouped_data = {} %}

{% for record in power_data %}
    {% set vendor = record.vendor | default('') | lower %}
    {% set group_key = record.sensor_type_label %}

    {% if group_key and group_key not in grouped_data %}
        {% set _ = grouped_data.update({group_key: record}) %}
    {% endif %}
{% endfor %}

<div style='width:100%;height:100%; padding:20px; display:flex; flex-direction:column;'>

  <div style='margin-bottom:15px; color:#424242; font-size:16px; font-weight:600;'>
    Sensor Health: {{ grouped_data|length }}
  </div>

  <div style="width:100%; flex:1; display:flex; gap:20px; overflow-x:auto;">

    {% if grouped_data %}

      {% for group_key, record in grouped_data.items() %}

        {% set sensor_type_label = record.sensor_type_label | default('') | lower %}
        {% set status = (
            record.sensor_status_label
            or 'N/A'
        ) | lower %}

        {% set heading =
            'Voltage AC' if 'voltsac' in sensor_type_label or 'voltsAC' in sensor_type_label else
            'Voltage DC' if 'voltsdc' in sensor_type_label or 'voltsDC' in sensor_type_label else
            'Voltage' if 'volts' in sensor_type_label else
            'Current' if 'ampere' in sensor_type_label else
            'Power' if 'watt' in sensor_type_label or 'power' in sensor_type_label else
            'Temperature' if 'celsius' in sensor_type_label or 'temperature' in sensor_type_label else
            'Fan' if 'rpm' in sensor_type_label or 'fan' in sensor_type_label else
            'Unknown'
        %}

        {% set color_map = {
            'ok': '#2e7d32',
            'normal': '#2e7d32',
            'active': '#2e7d32',
            'down': '#f39c12',
            'warning': '#f39c12',
            'critical': '#e74c3c',
            'shutdown': '#8e44ad',
            'unavailable': '#7f8c8d',
            'notSupported': '#7f8c8d',
            'not installed': '#7f8c8d',
            'nonoperational': '#95a5a6',

        } %}

        {% set color = color_map.get(status, '#95a5a6') %}

        <div style="display:flex; flex-direction:column; align-items:center;
                    padding:15px; border:1px solid #ddd;
                    border-radius:8px; min-width:200px; flex-shrink:0;">

          <div style='margin-bottom:8px; font-size:16px; font-weight:600;'>
            {{ heading }}
          </div>

          <div style="font-size:24px; font-weight:600; color:{{ color }};">
            {{ status | upper }}
          </div>

        </div>

      {% endfor %}

    {% else %}
      <div style="align-self:center;">No data available</div>
    {% endif %}

  </div>
</div>
{% endraw %}

{% raw %}
{% set target_ip = context.target_ip  %}
{% set power_query = "target_ip is '" ~ target_ip ~ "' and sensor_type_label is not empty" %}

{% set power_data = engine.query_stream_data(
    stream="rda_snmp_metrics",
    cfxql_query=power_query,
    sorting=[{"timestamp": "desc"}],
    limit=10000,
    max_rows=10000
) %}

{% set grouped_data = {} %}
{% if power_data and power_data|length > 0 %}
  {% for record in power_data %}
    {% set vendor = record.get("vendor", "") | string | lower %}
    {% if vendor == 'cisco' %}
      {# For Cisco: group by sensor_type_label #}
      {% set group_key = record.get("sensor_type_label", "") %}
      {% if group_key and group_key not in grouped_data %}
        {% set _ = grouped_data.update({group_key: record}) %}
      {% endif %}
    {% else %}
      {# For non-Cisco: group by sensor_type #}
      {% set group_key = record.get("sensor_type", "") %}
      {% if group_key and group_key not in grouped_data %}
        {% set _ = grouped_data.update({group_key: record}) %}
      {% endif %}
    {% endif %}
  {% endfor %}
{% endif %}

<div style='width:100%;height:100%; padding: 20px; display: flex; flex-direction: column;'>
  <div style='margin-bottom: 15px; color: #424242; font-size: 16px; font-weight: 600;'>
    Sensor Health: {{ grouped_data|length if grouped_data else 0 }}
  </div>
  
  <div style="width: 100%; flex: 1; display: flex; flex-direction: row; gap: 20px; overflow-x: auto; overflow-y: hidden;">
    {% if grouped_data and grouped_data|length > 0 %}
      {% for group_key in grouped_data %}
        {% set record = grouped_data[group_key] %}
        {% set sensor_status_label = record.get("sensor_status_label", "") %}
        {% set sensor_state = record.get("sensor_state", "") %}
        {% set sensor_type_label = record.get("sensor_type_label", "") | string | lower %}
        {% set vendor = record.get("vendor", "") | string | lower %}
        
        {% set display_value = sensor_status_label %}
        {% if not sensor_status_label or sensor_status_label|trim == '' %}
          {% if sensor_state and sensor_state|trim != '' %}
            {% set display_value = sensor_state %}
          {% else %}
            {% set display_value = 'Not Available' %}
          {% endif %}
        {% endif %}
        
        {# Determine heading - apply same mapping for all vendors #}
        {% set heading = group_key %}
        {# Map sensor_type_label to friendly names #}
        {% if 'voltsac' in sensor_type_label %}
          {% set heading = 'Voltage AC' %}
        {% elif 'voltsdc' in sensor_type_label %}
          {% set heading = 'Voltage DC' %}
        {% elif 'ampere' in sensor_type_label %}
          {% set heading = 'Current' %}
        {% elif 'watt' in sensor_type_label or 'power' in sensor_type_label %}
          {% set heading = 'Power' %}
        {% elif 'celsius' in sensor_type_label or 'celcius' in sensor_type_label or 'temperature' in sensor_type_label %}
          {% set heading = 'Temperature' %}
        {% elif 'rpm' in sensor_type_label or 'fan' in sensor_type_label %}
          {% set heading = 'Fan' %}
        {% else %}
          {% set heading = 'Unknown' %}
        {% endif %}
        
        {% set status = (display_value or 'N/A') | string | lower %}
        {% set color = '#95a5a6' %}
        {% if status == 'ok' %}{% set color = '#2e7d32' %}{% endif %}
        {% if status == 'down' %}{% set color = '#f39c12' %}{% endif %}
        {% if status == 'warning' %}{% set color = '#f39c12' %}{% endif %}
        {% if status == 'critical' %}{% set color = '#e74c3c' %}{% endif %}
        {% if status == 'shutdown' %}{% set color = '#8e44ad' %}{% endif %}
        {% if status == 'unavailable' %}{% set color = '#7f8c8d' %}{% endif %}
        {% if status == 'nonoperational' %}{% set color = '#95a5a6' %}{% endif %}
        
        <div style="display: flex; flex-direction: column; align-items: center; padding: 15px; border: 1px solid #ddd; border-radius: 8px; min-width: 200px; flex-shrink: 0;">
          <div style='text-align: center; margin-bottom: 8px; color: #424242; font-size: 16px; font-weight: 600;'>{{ heading }}</div>
          <div style="text-align: center; font-size: 24px; font-weight: 600; color: {{ color }};">{{ display_value or 'N/A' }}</div>
        </div>
      {% endfor %}
    {% else %}
      <div style="text-align: center; color: #424242; font-size: 14px; align-self: center;">No data available</div>
    {% endif %}
  </div>
</div>
{% endraw %}
